import{_ as a,o as t,c as l,a3 as r}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"SillyTavern 兼容性指南","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/agents/st-compatibility.md","filePath":"user-guide/tools/llm-chat/agents/st-compatibility.md","lastUpdated":1778244893000}'),i={name:"user-guide/tools/llm-chat/agents/st-compatibility.md"};function o(n,e,s,c,d,h){return t(),l("div",null,[...e[0]||(e[0]=[r('<div><h1 id="sillytavern-兼容性指南" tabindex="-1">SillyTavern 兼容性指南 <a class="header-anchor" href="#sillytavern-兼容性指南" aria-label="Permalink to &quot;SillyTavern 兼容性指南&quot;">​</a></h1><p>LLM Chat 深度兼容 SillyTavern (酒馆) 生态，支持导入其角色卡、预设消息和资源，让你能够无缝迁移已有的角色资产。</p><h2 id="_1-角色卡导入" tabindex="-1">1. 角色卡导入 <a class="header-anchor" href="#_1-角色卡导入" aria-label="Permalink to &quot;1. 角色卡导入&quot;">​</a></h2><p>系统支持以下格式的 SillyTavern 角色卡：</p><ul><li><strong>PNG 角色卡</strong>: 包含嵌入式元数据的图片文件。</li><li><strong>JSON 角色卡</strong>: 标准的角色定义文件。</li></ul><h3 id="导入流程" tabindex="-1">导入流程 <a class="header-anchor" href="#导入流程" aria-label="Permalink to &quot;导入流程&quot;">​</a></h3><ol><li>在 Agent 列表底部点击 <strong>...</strong> -&gt; <strong>「导入 SillyTavern 角色卡」</strong>。</li><li>选择本地的卡片文件。</li><li>系统将自动解析并填充： <ul><li><strong>基础信息</strong>: 名称、描述、性格。</li><li><strong>核心设定</strong>: 场景描述 (Scenario)、角色设定 (Description)。</li><li><strong>预设消息</strong>: 自动将 <code>First Message</code> 转换为开场白，将 <code>Alternate Greetings</code> 转换为可选预设。</li><li><strong>视觉资源</strong>: 自动提取 PNG 图片作为 Agent 图标。</li></ul></li></ol><h2 id="_2-消息注入策略兼容" tabindex="-1">2. 消息注入策略兼容 <a class="header-anchor" href="#_2-消息注入策略兼容" aria-label="Permalink to &quot;2. 消息注入策略兼容&quot;">​</a></h2><p>SillyTavern 用户熟悉的“深度注入”在 LLM Chat 中得到了完整保留并增强：</p><ul><li><strong>Depth (深度)</strong>: 控制消息在对话历史中的插入位置。</li><li><strong>高级深度语法</strong>: 支持 <code>3, 10~5</code> 这种多点或范围语法。</li><li><strong>角色映射</strong>: 自动处理 <code>char</code> 和 <code>user</code> 占位符的转换。</li></ul><h2 id="_3-正则管道与宏兼容" tabindex="-1">3. 正则管道与宏兼容 <a class="header-anchor" href="#_3-正则管道与宏兼容" aria-label="Permalink to &quot;3. 正则管道与宏兼容&quot;">​</a></h2><ul><li><strong>正则规则</strong>: 支持导入 SillyTavern 格式的正则替换规则文件。</li><li><strong>宏系统</strong>: 兼容常用的酒馆宏，如 <code>{{char}}</code>, <code>{{user}}</code>, <code>{{description}}</code> 等。</li></ul><h2 id="_4-资产文件迁移" tabindex="-1">4. 资产文件迁移 <a class="header-anchor" href="#_4-资产文件迁移" aria-label="Permalink to &quot;4. 资产文件迁移&quot;">​</a></h2><p>如果你导入的是一个包含子目录的复杂角色包，LLM Chat 会将其关联的媒体资源（图片、背景等）自动放入该 Agent 的私有<a href="./assets">资产目录</a>中，并保持原有的引用关系。</p><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./assets">Agent 资产管理</a></li><li><a href="./../context-pipeline/regex-pipeline">正则管道系统</a></li><li><a href="./../macro-system/macro-reference">宏系统参考</a></li></ul></div>',1)])])}const p=a(i,[["render",o]]);export{u as __pageData,p as default};
